import React, { useState } from 'react';
import './assets/styles/global.css';
import DashboardView from './features/dashboard/DashboardView';
import ConvoyView from './features/convoy/ConvoyView';
import LogbookView from './features/logbook/LogbookView';
import { Home, Users, BookOpen } from 'lucide-react';

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');

  return (
    <div className="app-container">
      <main className="content">
        {activeTab === 'dashboard' && <DashboardView setActiveTab={setActiveTab} />}
        {activeTab === 'convoy' && <ConvoyView />}
        {activeTab === 'logbook' && <LogbookView />}
      </main>

      {/* NAVIGATION BAR */}
      <nav style={navStyle}>
        <button onClick={() => setActiveTab('dashboard')} style={btnStyle(activeTab === 'dashboard')}>
          <Home size={20} /><span style={{fontSize:'10px'}}>Hem</span>
        </button>
        <button onClick={() => setActiveTab('convoy')} style={btnStyle(activeTab === 'convoy')}>
          <Users size={20} /><span style={{fontSize:'10px'}}>Konvoj</span>
        </button>
        <button onClick={() => setActiveTab('logbook')} style={btnStyle(activeTab === 'logbook')}>
          <BookOpen size={20} /><span style={{fontSize:'10px'}}>Logg</span>
        </button>
      </nav>
    </div>
  );
}

const navStyle = { position: 'fixed', bottom: 0, left: 0, right: 0, height: '70px', backgroundColor: '#FFF', borderTop: '1px solid #EEE', display: 'flex', justifyContent: 'space-around', alignItems: 'center', zIndex: 1000 };
const btnStyle = (active) => ({ border: 'none', background: 'none', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', color: active ? '#2D5A27' : '#BDC3C7', fontWeight: active ? 'bold' : 'normal' });

export default App;
